def candidate_files() -> Iterable[Path]:
    seen: set[Path] = set()
    prioritized: list[Path] = []
    fallback: list[Path] = []
    for root in candidate_roots():
        for path in root.rglob("*"):
            if not path.is_file() or path.suffix.lower() not in LOG_EXTENSIONS:
                continue
            path_text = str(path).lower()
            # Generated analysis files mention Liu Jie but are not source chat logs.
            if "/analysis/" in path_text or "/scripts/" in path_text:
                continue
            try:
                resolved = path.resolve()
            except OSError:
                continue
            if resolved in seen:
                continue
            if any(marker.lower() in path_text for marker in LIU_MARKERS):
                prioritized.append(path)
                seen.add(resolved)
                continue
            try:
                sample = path.read_text(encoding="utf-8", errors="ignore")[:5000]
            except OSError:
                continue
            if "刘姐" in sample:
                fallback.append(path)
                seen.add(resolved)

    # Prefer source chat/session logs over derived notes.
    for path in prioritized + fallback:
        yield path

